import{_ as s,o as e,c as i,ai as a}from"./chunks/framework.2e-g_11C.js";const g=JSON.parse('{"title":"Transform Files","description":"","frontmatter":{},"headers":[],"relativePath":"files/transform.md","filePath":"files/transform.md"}'),n={name:"files/transform.md"};function o(r,t,l,d,h,p){return e(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="transform-files" tabindex="-1">Transform Files <a class="header-anchor" href="#transform-files" aria-label="Permalink to “Transform Files”">​</a></h1><p>Images can be transformed via URL query parameters, commonly used to provide the most suitable size and file format. Files can be transformed using URL query parameters. If a processed asset does not yet exist, it is dynamically generated, stored, and returned.</p><h2 id="basic-transformations" tabindex="-1">Basic Transformations <a class="header-anchor" href="#basic-transformations" aria-label="Permalink to “Basic Transformations”">​</a></h2><p>Add the following query parameter to the end of your file URL:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>?width=200</span></span></code></pre></div><p>Your new URL should look like this:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://your-domain.com/assets/&lt;file-id&gt;?width=200</span></span></code></pre></div><p>Other transformation parameters include <code>height</code>, <code>quality</code>, <code>format</code>, and more. These transformations are applied on-the-fly and can be combined.</p><h2 id="custom-transformations" tabindex="-1">Custom Transformations <a class="header-anchor" href="#custom-transformations" aria-label="Permalink to “Custom Transformations”">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>width</code></td><td>How wide the image is in pixels.</td></tr><tr><td><code>height</code></td><td>How high the image is in pixels.</td></tr><tr><td><code>quality</code></td><td>The overall image quality (1 to 100). Higher value = larger file size, lower value = more compression.</td></tr><tr><td><code>withoutEnlargement</code></td><td>Disable automatically upscaling the image (true)</td></tr><tr><td><code>format</code></td><td>What file format to return the image in. Options: auto, jpg, png, webp, tiff. Auto defaults to webp/avif if supported, otherwise jpg.</td></tr><tr><td><code>fit</code></td><td>How the image should fit into the provided dimensions:<br>- <code>cover</code> (default): fit while preserving aspect ratio<br>- <code>contain</code>: contain within dimensions with letterboxing<br>- <code>inside</code>: resize as large as possible within dimensions<br>- <code>outside</code>: resize as small as possible within or beyond dimensions</td></tr></tbody></table><blockquote><p><strong>Focal Points</strong> When transforming an image with <code>width</code> and/or <code>height</code> parameters, the focal point is taken from the <code>focal_point_x</code> and <code>focal_point_y</code> coordinate values stored in the file object, cropping the image around these. This defaults to the image&#39;s centre.</p></blockquote><p><strong>Example Request:</strong></p><div class="language-http"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/assets/c984b755-e201-497e-b0a7-24156ad9c7e0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">width=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">300</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">height=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">300</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">quality=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">50</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">contain</span></span></code></pre></div><h2 id="advanced-transformations" tabindex="-1">Advanced Transformations <a class="header-anchor" href="#advanced-transformations" aria-label="Permalink to “Advanced Transformations”">​</a></h2><p>The system provides access to advanced image transformations using a <code>transforms</code> parameter. This parameter consists of a two-dimensional array. Each sub-array contains the name of the operation, followed by its arguments: <code>[[&quot;operation1&quot;, ...arguments], [&quot;operation2&quot;, ...otherArguments]]</code>.</p><blockquote><p><strong>REST Values</strong> When calling the REST API, datatypes like booleans need to be passed as strings.</p></blockquote><table tabindex="0"><thead><tr><th>Sharp API Call</th><th>transforms Equivalent</th></tr></thead><tbody><tr><td><code>.rotate(90)</code></td><td><code>[[&quot;rotate&quot;, 90]]</code></td></tr><tr><td><code>.rotate(90).blur(10).tint(255, 0, 255)</code></td><td><code>[[&quot;rotate&quot;, 90], [&quot;blur&quot;, 10], [&quot;tint&quot;, &quot;rgb(255, 0, 255)&quot;]]</code></td></tr><tr><td><code>negate({lower: 10, upper: 50})</code></td><td><code>[[&quot;negate&quot;, {&quot;lower&quot;: 10, &quot;upper&quot;: 50}]]</code></td></tr></tbody></table><p><strong>Example Request:</strong></p><div class="language-http"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/assets/c984b755-e201-497e-b0a7-24156ad9c7e0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">transforms=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">[[&quot;rotate&quot;, 90],[&quot;blur&quot;, 10],[&quot;tint&quot;, &quot;rgb(255, 0, 255)&quot;], [&quot;negate&quot;, {&quot;lower&quot;: 10, &quot;upper&quot;: 50}]]</span></span></code></pre></div><p>Custom and advanced transformations can also be used in conjunction.</p><p><strong>Example Request (combined):</strong></p><div class="language-http"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/assets/c984b755-e201-497e-b0a7-24156ad9c7e0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">transforms=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">[[&quot;flip&quot;]]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cover</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">width=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">300</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">height=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">100</span></span></code></pre></div><h2 id="preset-transformations" tabindex="-1">Preset Transformations <a class="header-anchor" href="#preset-transformations" aria-label="Permalink to “Preset Transformations”">​</a></h2><p>In order to mitigate the creation of a large number of files, you can restrict the transformations to a set of presets. You can create your own storage asset preset in the settings section.</p><p>The following options are available:</p><ul><li><strong>Allowed Transformations</strong>: for enabling, disabling, or limiting image transformations.</li><li><strong>Default Folder</strong>: sets the default folder where new assets are added. This does not affect existing files. Be aware that fields may override this value.</li><li><strong>Transformation Presets</strong>: sets a specific image transformation configuration to simplify requests or limit usage. <ul><li><strong>Key</strong>: sets unique identifier allowing faster and easier image transformation requests.</li><li><strong>Fit</strong>: contain (keeps aspect ratio), Cover (exact size), Fit Inside, or Fit Outside.</li><li><strong>Width</strong>: sets the width of the image.</li><li><strong>Height</strong>: sets the height of the image.</li><li><strong>Quality</strong>: adjusts the compression or quality of the image.</li><li><strong>Upscaling</strong>: when enabled, images won&#39;t be upscaled.</li><li><strong>Format</strong>: changes the output format.</li><li><strong>Additional Transformations</strong>: adds additional transformations using the underlying image processing library.</li></ul></li></ul><p>You can then use this <code>key</code> as a parameter when requesting a file to apply the preset.</p>`,27)])])}const k=s(n,[["render",o]]);export{g as __pageData,k as default};
